    "index_html",
    """You OWN exactly output/boids-simulation/index.html.
Write the full HTML per the contract:
- Minimal head with meta viewport, title "Boids Simulation", link to ./styles.css
- Body contains ONLY a <canvas id="boids-canvas"></canvas>
- Load <script type="module" src="./js/main.js"></script> at end of body.
Use a valid HTML5 structure.
write_file then done('ok').""",
    contract,
    model="fast",
)

# Delegate styles.css
h2 = delegate(
    "styles_css",
    """You OWN exactly output/boids-simulation/styles.css.
Write CSS to:
- Remove margins and scrollbars; full black background.
- Make canvas fill viewport (width:100vw; height:100vh) and display:block.
- Ensure smooth rendering; optionally set touch-action:none to avoid gestures.
write_file then done('ok').""",
    contract,
    model="fast",
)

# Delegate boid.js
h3 = delegate(
    "boid_js",
    """You OWN exactly output/boids-simulation/js/boid.js.
Implement per contract. Details:
- export class Boid { constructor(x, y, angle, speed, color) { ... } }
  Fields: x,y,vx,vy,size (e.g., 3.5), color (HSL string).
  Methods:
    - update(boids, width, height, dt, speed): applies alignment, cohesion, separation within radii
      Internal constants (no UI): PERCEPTION=55, SEPARATION_DIST=20, ALIGN_W=1.0, COHESION_W=0.8, SEPARATION_W=1.6, STEER=2.0 (blend rate 1/s).
      Compute neighbor aggregates; derive desired velocity directions for each rule; combine weights; blend current velocity toward the weighted desired using:
         vx += (desiredVx - vx) * STEER * dt
         vy += (desiredVy - vy) * STEER * dt
      Then renormalize (vx,vy) to magnitude 'speed' CONSTANT regardless of 'size'.
      Update position: x += vx * dt; y += vy * dt.
      Wrap around edges with a margin (2*size).
- export function spawnBoids(n, width, height, speed): returns array of Boid with random positions (0..width/height), random angle (0..2π), constant speed, vivid random hues (e.g., hsl(h,90%,60%)).
- Keep code efficient (no allocations in loops if possible); simple math is fine.
write_file then done('ok').""",
    contract,
    model="fast",
)

# Delegate simulation.js
h4 = delegate(
    "simulation_js",
    """You OWN exactly output/boids-simulation/js/simulation.js.
Implement per contract:
- import { Boid, spawnBoids } from "./boid.js";
- export class Simulation {
    constructor(width, height, count=300, speed=240) {
      this.width = width; this.height = height;
      this.speed = speed;
      this.boids = spawnBoids(count, width, height, speed);
    }
    update(dt) {
      const b = this.boids, w = this.width, h = this.height, s = this.speed;
      for (let i = 0; i < b.length; i++) b[i].update(b, w, h, dt, s);
    }
    resize(width, height) {
      this.width = width; this.height = height;
      // no re-spawn; boids will wrap into new bounds naturally
    }
    get boidsArray() { return this.boids; }
  }
- Ensure named export { Simulation }.
write_file then done('ok').""",
    contract,
    model="fast",
)

# Delegate renderer.js
h5 = delegate(
    "renderer_js",
    """You OWN exactly output/boids-simulation/js/renderer.js.
Implement per contract:
- export class Renderer {
    constructor(ctx) { this.ctx = ctx; this.width = 0; this.height = 0; }
    setSize(width, height){ this.width = width; this.height = height; }
    clear(){
      const ctx = this.ctx;
      ctx.clearRect(0, 0, this.width, this.height);
      // Optional subtle background:
      ctx.fillStyle = "#000";
      ctx.fillRect(0, 0, this.width, this.height);
    }
    draw(boids){
      const ctx = this.ctx;
      for (let i=0;i<boids.length;i++){
        const b = boids[i];
        const angle = Math.atan2(b.vy, b.vx);
        const s = b.size || 3.5;
        const head = s * 2.2;
        const wing = s * 1.2;
        const x = b.x, y = b.y;

        // Triangle points oriented along 'angle'
        const cos = Math.cos(angle), sin = Math.sin(angle);
        const x1 = x + cos * head,      y1 = y + sin * head;        // nose
        const x2 = x - cos * head + -sin * wing, y2 = y - sin * head +  cos * wing; // left
        const x3 = x - cos * head +  sin * wing, y3 = y - sin * head + -cos * wing; // right

        ctx.fillStyle = b.color || "#fff";
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.lineTo(x3, y3);
        ctx.closePath();
        ctx.fill();
      }
    }
  }
- Ensure named export { Renderer }.
write_file then done('ok').""",
    contract,
    model="fast",
)

# Delegate main.js
h6 = delegate(
    "main_js",
    """You OWN exactly output/boids-simulation/js/main.js.
Wire everything per contract. Details:
- import { Simulation } from "./simulation.js";
- import { Renderer } from "./renderer.js";
- Grab canvas#boids-canvas.
- function fitCanvas(canvas){
    const dpr = Math.max(1, Math.floor(window.devicePixelRatio || 1));
    const w = window.innerWidth, h = window.innerHeight;
    canvas.width = Math.floor(w * dpr);
    canvas.height = Math.floor(h * dpr);
    const ctx = canvas.getContext("2d");
    ctx.setTransform(dpr, 0, 0, dpr, 0, 0); // draw in CSS pixels
    return { ctx, width: w, height: h, dpr };
  }
- Initialize: const { ctx, width, height } = fitCanvas(canvas);
  const sim = new Simulation(width, height, 300, 240); // 300 boids, fast
  const renderer = new Renderer(ctx); renderer.setSize(width, height);
- Handle resize: on window resize, call fitCanvas again, update renderer.setSize and sim.resize.
- Animation loop:
    let last = performance.now();
    function frame(t){
      const dt = Math.min((t - last) / 1000, 0.05);
      last = t;
      sim.update(dt);
      renderer.clear();
      renderer.draw(sim.boidsArray);
      requestAnimationFrame(frame);
    }
    requestAnimationFrame(frame);
- No UI or config.
write_file then done('ok').""",
    contract,
    model="fast",
)

results = yield wait(h1, h2, h3, h4, h5, h6)

# Verify files exist
required = [
    "output/boids-simulation/index.html",
    "output/boids-simulation/styles.css",
    "output/boids-simulation/js/boid.js",
    "output/boids-simulation/js/simulation.js",
    "output/boids-simulation/js/renderer.js",
    "output/boids-simulation/js/main.js",
]
missing = [p for p in required if p not in ls("output/boids-simulation") and not os.path.exists(p)]
if missing:
    done(f"ERROR: Missing files: {missing}")

# Read back and sanity-check wiring
idx = read_file("output/boids-simulation/index.html")
mainjs = read_file("output/boids-simulation/js/main.js")
simjs = read_file("output/boids-simulation/js/simulation.js")
boidjs = read_file("output/boids-simulation/js/boid.js")
rendjs = read_file("output/boids-simulation/js/renderer.js")

issues = []

if 'id="boids-canvas"' not in idx:
    issues.append("index.html missing canvas with id 'boids-canvas'")
if 'type="module"' not in idx or 'src="./js/main.js"' not in idx:
    issues.append("index.html missing module script to ./js/main.js")
if "export class Boid" not in boidjs or "spawnBoids" not in boidjs:
    issues.append("boid.js missing Boid class or spawnBoids export")
if "export class Simulation" not in simjs or 'from "./boid.js"' not in simjs:
    issues.append("simulation.js missing Simulation class or import from boid.js")
if "export class Renderer" not in rendjs:
    issues.append("renderer.js missing Renderer class export")
if 'from "./simulation.js"' not in mainjs or 'from "./renderer.js"' not in mainjs:
    issues.append("main.js missing imports from simulation.js/renderer.js")
if "requestAnimationFrame" not in mainjs:
    issues.append("main.js missing animation loop")

if issues:
    done("Sanity check failed: " + "; ".join(issues))

# Final message
done("Boids simulation written to output/boids-simulation with modular JS (boid, simulation, renderer) and index.html entrypoint. Verified imports and animation loop wiring.")

